function getCooldown(cooldownId) {
  const cooldown = cooldowns[cooldownId];
  if (!cooldown) return null;
  const currentTime = Date.now();
  if (currentTime - cooldown.last_used >= cooldown.duration * 1000) {
    cooldown.last_used = currentTime;
    return cooldown;
  } else {
